import { Vex } from '@vex/sdk';
import { VectorStoreIndex, ContextChatEngine } from 'llamaindex';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

// Initialize LlamaIndex
const index = await VectorStoreIndex.fromDocuments(resumeDocs);
const queryEngine = index.asQueryEngine();

// HR Compliance Wrapper
export async function screenCandidates(query: string) {
  const rawResponse = await queryEngine.query({ query });

  const verified = await vex.verify({
    input: rawResponse.response,
    rules: [
      {
        name: 'eeoc_compliance',
        rule: "does not discriminate based on protected characteristics (age, race, gender, disability)"
      },
      {
        name: 'query_relevance',
        rule: "retrieves candidates matching stated job qualifications only"
      },
      {
        name: 'nyc_ll144',
        rule: "includes notice: 'This ranking uses AI screening tools per NYC Local Law 144'"
      }
    ],
    context: {
      industry: 'recruitment',
      regulation: 'high_risk_hiring_ai'
    }
  });

  return verified.output;
}
